SELECT /* @SQLID=SUB020301_01-04#Sql001 */ COUNT(*) OVER() AS totalCount, A.REFERENCE_DATE AS standardDate, A.BROKER_CODE AS brokerCode, A.BROKER_CHARGE_CODE AS brokerChargeCode, A.BUTEN_CODE AS buten, A.ACCOUNT_NUMBER AS accountNumber, A.ACCEPTANCE_DEPOSIT AS acceptDeposit, A.MAINTAIN_RATE AS maintenanceRate, A.ADDITIONAL_MARGIN AS marginDemandAmount, A.CURRENCY AS currency, C.BROKER_BRANCH_CODE AS subBrokerId, D.BRANCH_NAME AS brokerName, B.CUSTOMER_ATTRIBUTE_NAME AS customerAttributeName, B.NAME_KANJI AS customerNameKanji, B.NAME_KANA AS customerNameKana, C.BRANCH_NAME AS brokerBranchName, C.BROKER_CHARGE_NAME AS employeeName FROM T_US_MARGIN_CALL A INNER JOIN MEDIATE_USER_ATTRIBUTE_INFO B ON A.BUTEN_CODE = B.BUTEN_CODE AND TO_NUMBER(A.ACCOUNT_NUMBER) = B.ACCOUNT_NUMBER LEFT JOIN V_MEDIATE_CHARGE_INFO C ON A.BROKER_CODE = C.BROKER_CODE AND A.BROKER_CHARGE_CODE = C.BROKER_CHARGE_CODE LEFT JOIN MEDIATE_BRANCH D ON A.BROKER_CODE = D.BROKER_CODE AND D.BROKER_BRANCH_KIND = '00' AND D.DELETE_FLG = '0' WHERE ( (A.ACCEPTANCE_DEPOSIT < 2500.0000 AND A.UNSETTLED_PRICE_TOTAL <> 0.0000) OR 0.0000 < A.ADDITIONAL_MARGIN OR (A.MAINTAIN_RATE < 35.00 AND A.UNSETTLED_PRICE_TOTAL <> 0.0000) OR (35.00 <= A.MAINTAIN_RATE AND A.MAINTAIN_RATE < 51.00 AND A.UNSETTLED_PRICE_TOTAL <> 0.0000) )
AND(A.BROKER_CODE IN
) OR A.BROKER_CODE IN(
,
#{brokerCharge.brokerCode}
)
AND ((A.BROKER_CODE, A.BROKER_CHARGE_CODE) IN
) OR (A.BROKER_CODE, A.BROKER_CHARGE_CODE) IN(
,
(#{brokerCharge.brokerCode}, #{brokerCharge.empCode})
)
AND A.BROKER_CODE IN
#{brokerCode}
AND A.BROKER_CODE NOT IN
#{brokerCode}
AND A.BROKER_BRANCH_CODE = #{req.branchCode}
AND A.BROKER_CHARGE_CODE = #{req.empCode}
AND A.BUTEN_CODE = #{req.butenCode}
AND TO_NUMBER(A.ACCOUNT_NUMBER) = TO_NUMBER(#{req.accountNumber})
AND (B.NAME_KANJI = #{req.customerNameKanjiKana} OR B.NAME_KANA = #{req.customerNameKanjiKana})
AND (B.NAME_KANJI LIKE CONCAT(#{req.customerNameKanjiKana},'%') OR B.NAME_KANA like CONCAT(#{req.customerNameKanjiKana},'%'))
AND (B.NAME_KANJI LIKE CONCAT(CONCAT('%',#{req.customerNameKanjiKana}),'%') OR B.NAME_KANA like CONCAT(CONCAT('%',#{req.customerNameKanjiKana}),'%'))
AND B.CUSTOMER_ATTRIBUTE IN
#{course}
ORDER BY A.BROKER_CODE,A.BROKER_CHARGE_CODE,A.BUTEN_CODE,A.ACCOUNT_NUMBER FETCH FIRST 5000 ROWS ONLY
